import{_ as e,o,c as r,a5 as l}from"./chunks/framework.B5tqjWbr.js";const _=JSON.parse('{"title":"教程 0044：PCS 构网型 V/f 与下垂控制","description":"","frontmatter":{"title":"教程 0044：PCS 构网型 V/f 与下垂控制","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0044-pcs-grid-forming-vf-droop.html","status":"learning","visibility":"public","summary":"Imported from 0044-pcs-grid-forming-vf-droop.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0044-pcs-grid-forming-vf-droop.md","filePath":"content/power/lessons/0044-pcs-grid-forming-vf-droop.md","lastUpdated":null}'),i={name:"content/power/lessons/0044-pcs-grid-forming-vf-droop.md"};function t(n,a,d,c,p,s){return o(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="教程-0044-pcs-构网型-v-f-与下垂控制" tabindex="-1">教程 0044：PCS 构网型 V/f 与下垂控制 <a class="header-anchor" href="#教程-0044-pcs-构网型-v-f-与下垂控制" aria-label="Permalink to &quot;教程 0044：PCS 构网型 V/f 与下垂控制&quot;">​</a></h1><p>中文主讲。一个概念：构网型 PCS 自己建立电压和频率，像一个可控电压源。</p><p>目录</p><ul><li>它是什么</li><li>为什么 UPS 需要它</li><li>物理直觉</li><li>数学形式</li><li>一个仿真任务与仿真观察</li><li>固件落地</li><li>常见误解</li><li>验收标准、复盘问题、导师问题</li></ul><p>**保密边界：**只讲公开构网控制概念，不记录微网项目参数、并离网切换策略或客户现场配置。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>构网型控制（grid-forming control / GFM）不依赖外部电网相位，而是输出自己的电压幅值和频率。基础形式是电压频率控制（voltage-frequency control / V/f control），多机并联时常加入下垂控制（droop control）分配功率。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>UPS 离网逆变器本质上就是构建负载电压。PCS 在微网或孤岛场景也需要承担类似角色：没有强电网时，PCS 不能只跟随 PLL，而要建立电压源参考。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>GFL 是跟着别人打拍子，GFM 是自己当节拍器。下垂控制则像多个节拍器根据负载稍微放慢或降低电压，从而自然分担有功和无功。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>omega_ref = omega_nominal - Kp_droop * (P - P_ref) V_ref = V_nominal - Kq_droop * (Q - Q_ref) theta = theta + omega_ref * Ts</p><p>P-f 下垂让有功增加时频率略降；Q-V 下垂让无功增加时电压略降。具体符号依系统约定。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>给 GFM PCS 加阶跃负载，观察频率和电压按下垂曲线产生小偏移，再随二次控制或恢复环节回到目标附近。</p><p>产物</p><ul><li>一张 P/f 和 Q/V 下垂曲线。</li><li>一段说明：下垂是并联系统的功率分担机制，不是故障。</li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>模块常见命名包括 <code>virtual_oscillator</code>、<code>vf_reference</code>、<code>droop_controller</code>、<code>voltage_loop</code>、<code>current_limit</code>。构网模式尤其需要电流限幅和过载退让。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li>**误解：**构网型控制不需要电流环。 **纠正：**内层电流限制仍是保护功率器件的关键。</li><li>**误解：**频率偏移说明控制失败。 **纠正：**在下垂控制里，小偏移是功率分担信号。</li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能区分 GFL 和 GFM 的角度来源。</li><li>能写出 P-f、Q-V 下垂的基本式子。</li><li>能解释为什么构网 PCS 更像 UPS 离网逆变器。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>多台 PCS 并联时，为什么不能每台都死死维持同一个电压频率？</li><li>过载时先限电流还是先维持电压？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>公司项目中 GFL/GFM 的模式边界通常由状态机还是上位机指令决定？</li><li>我只记录公开模式分类，不记录现场参数。</li></ul><p>**下一步：**学习 PCS 并网侧 LCL 滤波器和有源阻尼。</p><p>源稿：<code>concepts/pcs/grid-forming-vf-droop.md</code></p><p>上一节：教程 0043：PCS 并网跟随型 P/Q 控制下一节：教程 0045：PCS LCL 滤波器与有源阻尼</p>',31)])])}const f=e(i,[["render",t]]);export{_ as __pageData,f as default};
